    "breadcrumb": "Báo cáo thực tập \u003e Workshop",
    "content": "Module 1: Storage \u0026 Database (Lưu trữ và Cơ sở dữ liệu)\rThiết lập bảng DynamoDB dạng Single Table để lưu trữ dữ liệu chung và S3 bucket để lưu trữ tài nguyên/tệp tin của ứng dụng.\nTạo tệp lib/storage-stack.ts:\nimport * as cdk from 'aws-cdk-lib'; import * as dynamodb from 'aws-cdk-lib/aws-dynamodb'; import * as s3 from 'aws-cdk-lib/aws-s3'; import { Construct } from 'constructs'; export class StorageStack extends cdk.Stack { public readonly table: dynamodb.Table; public readonly assetBucket: s3.Bucket; constructor(scope: Construct, id: string, props?: cdk.StackProps) { super(scope, id, props); // Khởi tạo DynamoDB Single Table cho dữ liệu ứng dụng nói chung this.table = new dynamodb.Table(this, 'AppSingleTable', { partitionKey: { name: 'PK', type: dynamodb.AttributeType.STRING }, sortKey: { name: 'SK', type: dynamodb.AttributeType.STRING }, billingMode: dynamodb.BillingMode.PAY_PER_REQUEST, // Thanh toán On-Demand pointInTimeRecovery: true, // Tự động backup liên tục removalPolicy: cdk.RemovalPolicy.DESTROY, // Tự động xóa khi destroy stack }); // Tạo S3 Bucket riêng tư để lưu trữ tài nguyên ứng dụng this.assetBucket = new s3.Bucket(this, 'AssetStorageBucket', { encryption: s3.BucketEncryption.S3_MANAGED, blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL, // Chặn hoàn toàn public access removalPolicy: cdk.RemovalPolicy.DESTROY, autoDeleteObjects: true, }); } }",
    "description": "Module 1: Storage \u0026 Database (Lưu trữ và Cơ sở dữ liệu)\rThiết lập bảng DynamoDB dạng Single Table để lưu trữ dữ liệu chung và S3 bucket để lưu trữ tài nguyên/tệp tin của ứng dụng.\nTạo tệp lib/storage-stack.ts:\nimport * as cdk from 'aws-cdk-lib'; import * as dynamodb from 'aws-cdk-lib/aws-dynamodb'; import * as s3 from 'aws-cdk-lib/aws-s3'; import { Construct } from 'constructs'; export class StorageStack extends cdk.Stack { public readonly table: dynamodb.Table; public readonly assetBucket: s3.Bucket; constructor(scope: Construct, id: string, props?: cdk.StackProps) { super(scope, id, props); // Khởi tạo DynamoDB Single Table cho dữ liệu ứng dụng nói chung this.table = new dynamodb.Table(this, 'AppSingleTable', { partitionKey: { name: 'PK', type: dynamodb.AttributeType.STRING }, sortKey: { name: 'SK', type: dynamodb.AttributeType.STRING }, billingMode: dynamodb.BillingMode.PAY_PER_REQUEST, // Thanh toán On-Demand pointInTimeRecovery: true, // Tự động backup liên tục removalPolicy: cdk.RemovalPolicy.DESTROY, // Tự động xóa khi destroy stack }); // Tạo S3 Bucket riêng tư để lưu trữ tài nguyên ứng dụng this.assetBucket = new s3.Bucket(this, 'AssetStorageBucket', { encryption: s3.BucketEncryption.S3_MANAGED, blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL, // Chặn hoàn toàn public access removalPolicy: cdk.RemovalPolicy.DESTROY, autoDeleteObjects: true, }); } }",
